3. Add a helper function to calculate trial progress percentage:
```typescript
function calculateTrialProgress(trialEndsAt: string | null): number {
  if (!trialEndsAt) return 100;

  const now = new Date();
  const trialEnd = new Date(trialEndsAt);
  const trialStart = new Date(trialEnd);
  trialStart.setMonth(trialStart.getMonth() - 1); // Assuming 1-month trial

  const totalDuration = trialEnd.getTime() - trialStart.getTime();
  const elapsed = now.getTime() - trialStart.getTime();

  const progress = Math.min(100, Math.max(0, (elapsed / totalDuration) * 100));
  return progress;
}
```

